import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"北海公园","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/beihai.md","filePath":"landmarks/beihai.md","lastUpdated":null}'),d={name:"landmarks/beihai.md"};function n(i,t,s,o,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="北海公园" tabindex="-1">北海公园 <a class="header-anchor" href="#北海公园" aria-label="Permalink to &quot;北海公园&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1508804185872-d7badad00f7d?w=1200" alt="北海公园"></p><blockquote><p>&quot;让我们荡起双桨，小船儿推开波浪，海面倒映着美丽的白塔，四周环绕着绿树红墙。&quot; —— 歌曲《让我们荡起双桨》</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>北海公园位于北京市中心区，是中国现存最古老、最完整的皇家园林之一。公园始建于辽代，历经金、元、明、清几个朝代的扩建，至今已有近千年的历史。</p><p>北海以琼华岛为中心，岛上建有著名的白塔，四周环绕着碧波荡漾的湖水和亭台楼阁，是中国古典园林艺术的杰作。1961年被国务院公布为第一批全国重点文物保护单位。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-21:00（旺季），6:30-20:00（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">门票10元，联票20元（含白塔）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">2-3小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋两季</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁6号线北海北站</td></tr><tr><td style="text-align:left;"><strong>预约方式</strong></td><td style="text-align:left;">可现场购票，旺季建议预约</td></tr></tbody></table><h2 id="主要景点" tabindex="-1">主要景点 <a class="header-anchor" href="#主要景点" aria-label="Permalink to &quot;主要景点&quot;">​</a></h2><h3 id="琼华岛与白塔" tabindex="-1">琼华岛与白塔 <a class="header-anchor" href="#琼华岛与白塔" aria-label="Permalink to &quot;琼华岛与白塔&quot;">​</a></h3><p>琼华岛是北海公园的中心，岛上建有著名的永安寺白塔，是北海的标志。</p><p><img src="https://images.unsplash.com/photo-1590549016683-3775f8b36b08?w=800" alt="北海白塔"></p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>白塔高度</strong></td><td style="text-align:left;">35.9米</td></tr><tr><td style="text-align:left;"><strong>建造年代</strong></td><td style="text-align:left;">清顺治八年（1651年）</td></tr><tr><td style="text-align:left;"><strong>建筑风格</strong></td><td style="text-align:left;">藏式喇嘛塔</td></tr></tbody></table><p>登临白塔可俯瞰全园，远眺故宫、景山、中南海，视野开阔，令人心旷神怡。</p><h3 id="九龙壁" tabindex="-1">九龙壁 <a class="header-anchor" href="#九龙壁" aria-label="Permalink to &quot;九龙壁&quot;">​</a></h3><p>位于北海公园北岸，是中国现存三座九龙壁中最精美的一座。壁上九条大龙，形态各异，栩栩如生。</p><h3 id="五龙亭" tabindex="-1">五龙亭 <a class="header-anchor" href="#五龙亭" aria-label="Permalink to &quot;五龙亭&quot;">​</a></h3><p>位于北岸，由五座造型各异的亭子组成，是皇帝垂钓和观赏焰火的地方。</p><h3 id="团城" tabindex="-1">团城 <a class="header-anchor" href="#团城" aria-label="Permalink to &quot;团城&quot;">​</a></h3><p>位于北海公园南门内，是一座圆形城台，台上建有承光殿，供奉白玉佛。著名的渎山大玉海就在此处。</p><h2 id="文化故事" tabindex="-1">文化故事 <a class="header-anchor" href="#文化故事" aria-label="Permalink to &quot;文化故事&quot;">​</a></h2><h3 id="让我们荡起双桨" tabindex="-1">&quot;让我们荡起双桨&quot; <a class="header-anchor" href="#让我们荡起双桨" aria-label="Permalink to &quot;&quot;让我们荡起双桨&quot;&quot;">​</a></h3><p>1955年，电影《祖国的花朵》在北海取景，插曲《让我们荡起双桨》唱遍大江南北，歌词中的&quot;海面倒映着美丽的白塔，四周环绕着绿树红墙&quot;成为北海最经典的写照。</p><h3 id="渎山大玉海的传奇" tabindex="-1">渎山大玉海的传奇 <a class="header-anchor" href="#渎山大玉海的传奇" aria-label="Permalink to &quot;渎山大玉海的传奇&quot;">​</a></h3><p>团城上的渎山大玉海是元代的巨型酒器，由一整块墨玉雕刻而成，重约3.5吨。传说当年忽必烈曾用它盛酒，宴请群臣。明末被当作腌菜缸使用，清代才被重新发现。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典半日游（2-3小时）</strong>： 南门（团城）→ 琼华岛 → 白塔 → 永安寺 → 沿湖漫步 → 五龙亭 → 九龙壁 → 北门出</p><h3 id="划船游湖" tabindex="-1">划船游湖 <a class="header-anchor" href="#划船游湖" aria-label="Permalink to &quot;划船游湖&quot;">​</a></h3><p>北海公园是北京著名的划船胜地：</p><table tabindex="0"><thead><tr><th style="text-align:left;">船型</th><th style="text-align:center;">价格</th><th style="text-align:left;">适合</th></tr></thead><tbody><tr><td style="text-align:left;">手划船</td><td style="text-align:center;">60元/小时</td><td style="text-align:left;">情侣、朋友</td></tr><tr><td style="text-align:left;">脚踏船</td><td style="text-align:center;">80元/小时</td><td style="text-align:left;">家庭</td></tr><tr><td style="text-align:left;">电动船</td><td style="text-align:center;">100元/小时</td><td style="text-align:left;">省力游览</td></tr></tbody></table><h3 id="最佳拍照点" tabindex="-1">最佳拍照点 <a class="header-anchor" href="#最佳拍照点" aria-label="Permalink to &quot;最佳拍照点&quot;">​</a></h3><ol><li><strong>白塔前</strong>：经典角度，绿树红墙白塔</li><li><strong>五龙亭</strong>：拍北海全景</li><li><strong>琼华岛东侧</strong>：拍湖面倒影</li></ol><h2 id="交通指南" tabindex="-1">交通指南 <a class="header-anchor" href="#交通指南" aria-label="Permalink to &quot;交通指南&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">入口</th><th style="text-align:left;">交通方式</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>南门</strong></td><td style="text-align:left;">公交101、103、109路北海站</td></tr><tr><td style="text-align:left;"><strong>东门</strong></td><td style="text-align:left;">地铁6号线北海北站B口（最方便）</td></tr><tr><td style="text-align:left;"><strong>北门</strong></td><td style="text-align:left;">公交107、111、118路北海北门站</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">景山公园</td><td style="text-align:center;">500米</td><td style="text-align:left;">俯瞰故宫</td></tr><tr><td style="text-align:left;">故宫</td><td style="text-align:center;">800米</td><td style="text-align:left;">明清皇宫</td></tr><tr><td style="text-align:left;">什刹海</td><td style="text-align:center;">300米</td><td style="text-align:left;">老北京风情</td></tr></tbody></table><hr><p><strong>💡 Tips</strong>：北海公园是北京最具皇家气派的公园之一，建议安排半天时间慢慢游览。春天赏花、夏天划船、秋天看银杏、冬天滑冰，四季皆宜。</p>',39)])])}const b=e(d,[["render",n]]);export{f as __pageData,b as default};
